def n_sansli_bilet(n):
    def asal(x):
        if x < 2:
            return False
        d = 2
        while d * d <= x:
            if x % d == 0:
                return False
            d += 1
        return True
    numara = 1
    bulunan = 0
    while bulunan < n:
        numara += 1
        if asal(numara):
            bulunan += 1
    return numara
